import { ChromaClient } from "chromadb";

const client = new ChromaClient({ path: "http://localhost:8000" });
const collection = await client.getOrCreateCollection({
  name: "articles",
  metadata: { "hnsw:space": "cosine" },
});
console.log("collection ready, count =", await collection.count());

await collection.add({
  ids: ["a1", "a2", "a3", "a4"],
  documents: [
    "How to tune PostgreSQL for heavy write workloads",
    "A beginner's guide to baking sourdough bread",
    "Scaling Kubernetes clusters past 1000 nodes",
    "Why your sourdough starter keeps dying",
  ],
  metadatas: [
    { topic: "databases", year: 2024 },
    { topic: "cooking", year: 2023 },
    { topic: "devops", year: 2024 },
    { topic: "cooking", year: 2024 },
  ],
});
console.log("count =", await collection.count()); // 4

const results = await collection.query({
  queryTexts: ["my bread won't rise"],
  nResults: 2,
});
console.log("unfiltered:", results.documents[0]);

const filtered = await collection.query({
  queryTexts: ["my bread won't rise"],
  nResults: 2,
  where: { $and: [{ topic: "cooking" }, { year: { $gte: 2024 } }] },
});
console.log("cooking+2024:", filtered.documents[0]);
// Only 'Why your sourdough starter keeps dying' survives the filter.

await collection.update({
  ids: ["a2"],
  documents: ["An advanced guide to baking sourdough bread at home"],
  metadatas: [{ topic: "cooking", year: 2025 }],
});
const got = await collection.get({ ids: ["a2"] });
console.log(got.documents); // updated text

await collection.delete({ ids: ["a1"] });                 // delete by id
await collection.delete({ where: { topic: "devops" } });  // delete by filter
console.log("count after deletes =", await collection.count()); // 2

