const texts = [
  "The mitochondria is the powerhouse of the cell",
  "Postgres supports JSONB for semi-structured data",
  "Our office is closed on public holidays",
  "pgvector adds approximate nearest neighbor search to Postgres",
];
const resp = await openai.embeddings.create({
  model: "text-embedding-3-small",
  input: texts,
});
const rows = texts.map((content, i) => ({
  content,
  embedding: resp.data[i].embedding,
}));
const { error } = await supabase.from("documents").insert(rows);
if (error) throw error;
console.log("inserted", rows.length, "rows");

const qResp = await openai.embeddings.create({
  model: "text-embedding-3-small",
  input: "how do I search vectors in Postgres?",
});
const q = qResp.data[0].embedding;

const { data, error } = await supabase.rpc("match_documents", {
  query_embedding: q,
  match_count: 3,
});
if (error) throw error;
for (const row of data) {
  console.log(row.similarity.toFixed(4), row.content);
}
// Top hit: 'pgvector adds approximate nearest neighbor search...'

// Raw SQL equivalent (SQL Editor):
// select content, 1 - (embedding <=> '[0.01, ...]') as similarity
// from documents order by embedding <=> '[0.01, ...]' limit 3;

// npm install hnswlib-node

const DIM = 128, N = 10000;

function randomVector(dim) {
  return Array.from({ length: dim }, () => Math.random());
}
const data = Array.from({ length: N }, () => randomVector(DIM));
const queries = Array.from({ length: 100 }, () => randomVector(DIM));
console.log("data:", data.length, "queries:", queries.length);

function bruteForceTop10(q) {
  const scored = data.map((v, i) => {
    let s = 0;
    for (let d = 0; d < DIM; d++) s += (v[d] - q[d]) ** 2;
    return { i, dist: s }; // squared euclidean: same ranking
  });
  scored.sort((a, b) => a.dist - b.dist);
  return scored.slice(0, 10).map((x) => x.i);
}

const t0 = performance.now();
const groundTruth = queries.map(bruteForceTop10);
const flatMs = (performance.now() - t0) / queries.length;
console.log(`flat search: ${flatMs.toFixed(2)} ms/query (exact by definition)`);

import { HierarchicalNSW } from "hnswlib-node";

const index = new HierarchicalNSW("l2", DIM);
index.initIndex(N, 16, 200); // maxElements, M, efConstruction

const tBuild = performance.now();
for (let i = 0; i < N; i++) index.addPoint(data[i], i);
console.log(
  `built HNSW over ${N} vectors in ${((performance.now() - tBuild) / 1000).toFixed(2)}s`
);

index.setEf(50); // search-time quality knob (must be >= k)

const t1 = performance.now();
const hnswResults = queries.map((q) => index.searchKnn(q, 10).neighbors);
const hnswMs = (performance.now() - t1) / queries.length;

let recall = 0;
for (let i = 0; i < queries.length; i++) {
  const truth = new Set(groundTruth[i]);
  recall += hnswResults[i].filter((x) => truth.has(x)).length / 10;
}
recall /= queries.length;

console.log(`flat: ${flatMs.toFixed(2)} ms/query | recall@10 = 1.000`);
console.log(`hnsw: ${hnswMs.toFixed(2)} ms/query | recall@10 = ${recall.toFixed(3)}`);
console.log(`speedup: ${(flatMs / hnswMs).toFixed(0)}x`);
// Typical: ~20-50x faster at ~0.95+ recall. Try index.setEf(10) vs 200.

