import numpy as np

def dot(a, b):
    return float(np.dot(a, b))

def cosine(a, b):
    return float(np.dot(a, b) / (np.linalg.norm(a) * np.linalg.norm(b)))

def euclidean(a, b):
    return float(np.linalg.norm(np.array(a) - np.array(b)))

print("metrics defined")

steps.javascript:
// No install needed — plain Node (save as metrics.mjs, run: node metrics.mjs)

export function dot(a, b) {
  return a.reduce((s, x, i) => s + x * b[i], 0);
}

export function norm(a) {
  return Math.sqrt(dot(a, a));
}

export function cosine(a, b) {
  return dot(a, b) / (norm(a) * norm(b));
}

export function euclidean(a, b) {
  return Math.sqrt(a.reduce((s, x, i) => s + (x - b[i]) ** 2, 0));
}

console.log("metrics defined");

const a = [1.0, 2.0, 3.0];
const b = [1.1, 2.1, 2.9];        // nearby point, similar direction
const c = a.map((x) => x * 10);    // same direction, 10x magnitude

for (const [name, v] of [["b (nearby)", b], ["c (scaled 10x)", c]]) {
  console.log(`a vs ${name}:`);
  console.log(`  cosine    = ${cosine(a, v).toFixed(4)}`);
  console.log(`  dot       = ${dot(a, v).toFixed(2)}`);
  console.log(`  euclidean = ${euclidean(a, v).toFixed(4)}`);
}
// cosine ranks c first (1.0000), euclidean ranks b first,
// dot gives c a huge score purely from magnitude.

