def normalize(v):
    v = np.array(v, dtype=float)
    return v / np.linalg.norm(v)

an, bn, cn = normalize(a), normalize(b), normalize(c)

for name, v in [("b_norm", bn), ("c_norm", cn)]:
    cos, dp, eu = cosine(an, v), dot(an, v), euclidean(an, v)
    print(f"a_norm vs {name}: cos={cos:.4f} dot={dp:.4f} eucl={eu:.4f}")
    print(f"  check: 2 - 2*cos = {2 - 2*cos:.4f} ~= eucl^2 = {eu**2:.4f}")
# cos == dot exactly; euclidean now gives the same ranking too.

