function normalize(v) {
  const n = norm(v);
  return v.map((x) => x / n);
}

const an = normalize(a), bn = normalize(b), cn = normalize(c);

for (const [name, v] of [["b_norm", bn], ["c_norm", cn]]) {
  const cos = cosine(an, v), dp = dot(an, v), eu = euclidean(an, v);
  console.log(
    `a_norm vs ${name}: cos=${cos.toFixed(4)} dot=${dp.toFixed(4)} eucl=${eu.toFixed(4)}`
  );
  console.log(
    `  check: 2 - 2*cos = ${(2 - 2 * cos).toFixed(4)} ~= eucl^2 = ${(eu * eu).toFixed(4)}`
  );
}
// cos == dot exactly; euclidean now gives the same ranking too.

function topK(queryVec, docVecs, docs, k = 3, minScore = 0.3) {
  return docVecs
    .map((v, i) => ({ score: cosine(queryVec, v), doc: docs[i] }))
    .sort((x, y) => y.score - x.score)
    .slice(0, k)
    .filter((r) => r.score >= minScore);
}

const docs = Array.from({ length: 8 }, (_, i) => `doc-${i}`);
const docVecs = docs.map(() =>
  Array.from({ length: 4 }, () => Math.random() * 2 - 1)
);
const query = docVecs[2].map((x) => x + (Math.random() - 0.5) * 0.2); // near doc-2

for (const { score, doc } of topK(query, docVecs, docs, 3, 0.3)) {
  console.log(score.toFixed(4), doc);
}
// doc-2 first; weak matches below 0.3 are dropped entirely.
